// Generated by AI (UnitTest MCP)
use crate::{now_unix, telemetry, MindLeak, Result};

impl MindLeak {
    /// Record one observability event about a tool invocation (ADR-0010).
    /// Best-effort: a telemetry write failure is logged and swallowed so it can
    /// never change the result of the operation being observed.
    pub fn record_tool_call(
        &self,
        tool: &str,
        ok: bool,
        duration_ms: i64,
        detail: Option<serde_json::Value>,
    ) {
        let outcome = if ok { "ok" } else { "error" };
        if let Err(e) = telemetry::record(
            &self.store.conn,
            now_unix(),
            "tool_call",
            tool,
            outcome,
            Some(duration_ms),
            detail.as_ref(),
        ) {
            tracing::warn!(target: "mindleak::telemetry", tool, error = %e, "failed to record telemetry");
        }
    }

    /// Record one autonomous maintenance pass without exposing it as a tool
    /// invocation. Best-effort for the same reason as tool telemetry.
    pub fn record_maintenance(
        &self,
        name: &str,
        outcome: &str,
        duration_ms: i64,
        detail: Option<serde_json::Value>,
    ) {
        if let Err(error) = telemetry::record(
            &self.store.conn,
            now_unix(),
            "maintenance",
            name,
            outcome,
            Some(duration_ms),
            detail.as_ref(),
        ) {
            tracing::warn!(target: "mindleak::telemetry", name, %error, "failed to record maintenance telemetry");
        }
    }

    /// A point-in-time observability snapshot: aggregate metrics per tool plus
    /// the most recent `recent_limit` events (ADR-0010).
    pub fn telemetry_snapshot(&self, recent_limit: usize) -> Result<telemetry::Snapshot> {
        telemetry::snapshot(&self.store.conn, recent_limit)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn maintenance_telemetry_is_distinct_from_tool_calls() {
        let engine = MindLeak::open_in_memory().unwrap();

        engine.record_maintenance(
            "autonomous_consolidation",
            "skipped",
            3,
            Some(serde_json::json!({ "reason": "no_candidates" })),
        );

        let snapshot = engine.telemetry_snapshot(1).unwrap();
        assert_eq!(snapshot.recent[0].kind, "maintenance");
        assert_eq!(snapshot.recent[0].outcome, "skipped");
    }
}
